import sailpoint.object.Entitlement;

// Validate required parameters
if (applicationName == null || applicationName.isEmpty()) {
  throw new Exception("applicationName is required");
}
if (groupName == null || groupName.isEmpty()) {
  throw new Exception("groupName is required");
}
if (groupDescription == null || groupDescription.isEmpty()) {
  throw new Exception("groupDescription is required");
}

log.info("Input validation successful for application: " + applicationName + ", group: " + groupName);
return "VALIDATED";

import sailpoint.object.Application;
import sailpoint.object.QueryOptions;

QueryOptions qo = new QueryOptions();
qo.addFilter("name", applicationName);

Application app = context.getObjectByQuery(Application.class, qo);

if (app == null) {
  throw new Exception("Application not found: " + applicationName);
}

log.info("Retrieved application: " + app.getName() + " (ID: " + app.getId() + ")");
return app;

import sailpoint.object.Entitlement;
import sailpoint.object.QueryOptions;

QueryOptions qo = new QueryOptions();
qo.addFilter("name", groupName);
qo.addFilter("applicationId", application.getId());

Entitlement existingEntitlement = context.getObjectByQuery(Entitlement.class, qo);

if (existingEntitlement != null) {
  log.warn("Entitlement group already exists: " + groupName);
  return existingEntitlement;
}

log.info("No existing entitlement found with name: " + groupName);
return null;

createdGroupId = existingGroup.getId();
workflowResult = "GROUP_ALREADY_EXISTS";
log.info("Entitlement group already exists with ID: " + createdGroupId);
return createdGroupId;

import sailpoint.object.Entitlement;

Entitlement entitlement = new Entitlement();
entitlement.setName(groupName);
entitlement.setDisplayName(displayName != null ? displayName : groupName);
entitlement.setDescription(groupDescription);
entitlement.setApplicationId(application.getId());

// Set the type to "group" if the application supports it
entitlement.setAttribute("type", "group");

// Set owner if provided
if (groupOwner != null && !groupOwner.isEmpty()) {
  entitlement.setOwner(groupOwner);
}

// Save the new entitlement
context.saveObject(entitlement);
context.commitTransaction();

log.info("Successfully created entitlement group: " + groupName + " (ID: " + entitlement.getId() + ")");
workflowResult = "SUCCESS";

return entitlement.getId();

workflowResult = "ERROR";
log.error("Workflow error: " + exception.getMessage());
return exception.getMessage();
